impl ParseResult {
    /// Get all capture names
    pub fn capture_names(&self) -> Vec<&String>;

    /// Get a specific capture by name
    pub fn get_capture(&self, name: &str, input: &str) -> Option<&str>;

    /// Get all captures as a HashMap
    pub fn captures(&self, input: &str) -> HashMap<&str, &str>;
}

