require 'parsanol'

class MyParser < Parsanol::Parser
  rule(:integer) { match('[0-9]').repeat(1) }
  rule(:plus)    { str('+') }
  rule(:expr)    { integer >> plus >> integer }

  root :expr
end

parser = MyParser.new
result = parser.parse('1+2')

// JSON parser in 50 lines
let grammar = GrammarBuilder::new()
    .rule("value", choice([
        str("true"), str("false"), str("null"),
        rule_ref("number"), rule_ref("string"),
        rule_ref("array"), rule_ref("object"),
    ]))
    .rule("number", re(r"-?[0-9]+(\.[0-9]+)?([eE][+-]?[0-9]+)?"))
    .build();

